class Solution {
public:
    int longestSemiRepetitiveSubstring(string s) {
        int res = 0, cur = 0, prev = -1;
        for (char c : s) {
            if (c == '0' && prev == '0') cur = 1;
            else cur++;
            res = max(res, cur);
            prev = c - '0';
        }
        return res;
    }
};
```
